def _resolve_workbook(workspace_path, case, filename):
    """Read case/filename from the unzipped folder; else from a zip
    (canonical <case>.zip preferred); else return (None, None) -> fail closed."""
    root = Path(workspace_path)
    direct = root / case / filename
    if direct.exists():
        return openpyxl.load_workbook(direct), str(direct)
    zips = []
    canonical = root / (case + '.zip')
    if canonical.exists():
        zips.append(canonical)
    for z in sorted(root.rglob('*.zip')):
        if z not in zips:
            zips.append(z)
    for zp in zips:
        try:
            with zipfile.ZipFile(zp) as zf:
                members = [m for m in zf.namelist() if '__MACOSX' not in m and not m.endswith('/')]
                for m in members:
                    if m.endswith(case + '/' + filename):
                        return openpyxl.load_workbook(io.BytesIO(zf.read(m))), zp.name + '::' + m
                if zp.stem == case:
                    for m in members:
                        if m.rsplit('/', 1)[-1] == filename:
                            return openpyxl.load_workbook(io.BytesIO(zf.read(m))), zp.name + '::' + m
        except zipfile.BadZipFile:
            continue
    return None, None

