        if h.lower().replace(' ', '_') == 'drug_dose_grams' or h.lower() == 'drug_dose_grams' or h == 'Drug_Dose_Grams':
            drug_dose_col = idx

    # If we can't find headers by name, also try checking all cells in row 2
    row2_values = [str(cell.value).strip() if cell.value is not None else '' for cell in ws[2]]

    has_octagam = False
    has_40 = False

    if drug_name_col is not None:
