    feedback_parts.append(f"Has Octagam in Drug_Name: {has_octagam}")
    feedback_parts.append(f"Has 40 in Drug_Dose_Grams: {has_40}")

    # The rubric says row 2 must NOT contain Octagam in Drug_Name OR 40 in Drug_Dose_Grams
    # This means NEITHER should be present (interpreting "or" as logical or: not(A or B) = not A and not B)
    if has_octagam or has_40:
        return {"pass": False, "score": 0.0, "feedback": f"FAIL: Row 2 still contains forbidden values. Octagam found: {has_octagam}, 40 found: {has_40}. {'; '.join(feedback_parts)}"}
    else:
        return {"pass": True, "score": 1.0, "feedback": f"PASS: Row 2 does not contain Octagam in Drug_Name or 40 in Drug_Dose_Grams. {'; '.join(feedback_parts)}"}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": "external_services_path is None; cannot check slack_data.json"}

    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0,
                "feedback": "slack_data.json not found in external_services_path"}

    def normalize_dashes(s):
        # Treat em-dash, en-dash, figure-dash all as plain hyphen
        return s.replace('\u2014', '-').replace('\u2013', '-').replace('\u2012', '-')

    try:
        with open(slack_path, 'r', encoding='utf-8') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0,
                "feedback": f"Failed to read/parse slack_data.json: {e}"}

    # Find the intake-alerts channel id
    channels = slack_data.get('channels', {})
    intake_alerts_id = None
    for cid, cinfo in channels.items():
        if cinfo.get('name', '').lower() == 'intake-alerts':
            intake_alerts_id = cid
            break

    if intake_alerts_id is None:
        return {"pass": False, "score": 0.0,
                "feedback": f"Could not find #intake-alerts channel in slack_data.json. "
                            f"Available channels: {[v.get('name') for v in channels.values()]}"}

    messages = slack_data.get('messages', {}).get(intake_alerts_id, [])
    if not messages:
        return {"pass": False, "score": 0.0,
                "feedback": "Found #intake-alerts channel but no messages in it."}

    # Required prefix (must be present)
    required_prefix = normalize_dashes('[PA HOLD] Webb_03151968 — invalid:')
    # Alternatives (at least one must be present)
    alt_filename = 'igglevel_09292025.pdf'
    alt_phrase   = 'Most recent IgG lab result'

    for msg in messages:
        msg_text = msg.get('text', '') if isinstance(msg, dict) else str(msg)
        msg_norm = normalize_dashes(msg_text)

        has_prefix = required_prefix in msg_norm
        has_alt    = (alt_filename in msg_norm) or (alt_phrase.lower() in msg_norm.lower())

        if has_prefix and has_alt:
            return {"pass": True, "score": 1.0,
                    "feedback": f"Found matching [PA HOLD] message in #intake-alerts: '{msg_text}'"}

    all_texts = [msg.get('text', '') if isinstance(msg, dict) else str(msg) for msg in messages]
    return {"pass": False, "score": 0.0,
            "feedback": (f"Did not find a message in #intake-alerts containing "
                         f"'{required_prefix}' AND ('{alt_filename}' OR '{alt_phrase}'). "
                         f"Messages found: {all_texts}")}

