from pathlib import Path
import json, re, unicodedata

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox.json'}

    mailbox_file = Path(external_services_path) / 'mailbox.json'
    if not mailbox_file.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found in external_services_path'}

    try:
        with open(mailbox_file, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading mailbox.json: {e}'}

    def normalize(s):
        s = unicodedata.normalize('NFKC', s)
        s = s.lower()
        s = s.replace('\u2014', '-').replace('\u2013', '-').replace('\u2012', '-')
        s = s.replace('\u2018', "'").replace('\u2019', "'").replace('\u201c', '"').replace('\u201d', '"')
        s = re.sub(r'\s+', ' ', s)
        return s.strip()

    expected_subject = 'Unable to Contact Patient  | CASE_ID: Rodriguez_07221975'

    # Ordered list of required fragments. The salutation accepts either form.
    fragments = [
        ("Salutation",        ["Dear Dr. Robert Cho,", "Dear Dr. Cho,"]),
        ("Referral line",     ["We received a referral for Carmen Rodriguez (DOB: 07221975)."]),
        ("Contact attempts",  ["After 3 contact attempts, we have been unable to reach the patient"]),
        ("Phone number",      ["at the number on file: (555) 618-9043."]),
        ("Attempt 1",         ["Attempt 1: 2026-03-25 10:15 — Voicemail"]),
        ("Attempt 2",         ["Attempt 2: 2026-03-26 14:30 — No Answer"]),
        ("Attempt 3",         ["Attempt 3: 2026-03-28 09:00 — Voicemail"]),
        ("Closing request",   ["Please provide an alternate contact or assist in connecting the patient"]),
        ("Closing statement", ["with our team. We cannot proceed until contact is established."]),
    ]

    emails = data.get('emails', [])
    for email in emails:
        subject = email.get('subject', '')
        folder  = email.get('folder', '')
        body    = email.get('body_text', '')

        subject_match = normalize(subject) == normalize(expected_subject)
        folder_match  = folder.strip().lower() == 'sent'

        if subject_match and folder_match:
            body_n = normalize(body)

            # Walk through fragments in order. For each one, find the earliest
            # accepted variant at or after the current cursor position.
            cursor = 0
            missing = []
            out_of_order = []
            for label, variants in fragments:
                best_pos = -1
                for v in variants:
                    pos = body_n.find(normalize(v), cursor)
                    if pos != -1 and (best_pos == -1 or pos < best_pos):
                        best_pos = pos
                if best_pos == -1:
                    # Check if it exists anywhere (before the cursor) to distinguish
                    # "missing" from "out of order".
                    anywhere = any(normalize(v) in body_n for v in variants)
                    if anywhere:
                        out_of_order.append(label)
                    else:
                        missing.append(label)
                else:
                    cursor = best_pos + 1

            total  = len(fragments)
            passed = total - len(missing) - len(out_of_order)
            score  = round(passed / total, 2)

            if not missing and not out_of_order:
                return {'pass': True, 'score': 1.0,
                        'feedback': f'Sent email with correct subject contains all {total} required body fragments in the correct order.'}
            else:
                problems = []
                if missing:
                    problems.append(f'missing: {missing}')
                if out_of_order:
                    problems.append(f'out of order: {out_of_order}')
                return {'pass': False, 'score': score,
                        'feedback': f'Email found but body fragment issues — ' + '; '.join(problems)}

    return {'pass': False, 'score': 0.0,
            'feedback': f'No sent email found with subject "{expected_subject.strip()}" in Sent folder.'}
